#include<bits/stdc++.h>
using namespace std;
map<int,int>m;
int main()
{
	int t;
	cin>>t;
	while(t--){
		int x,n;
		cin>>x>>n;
		if(x==1){
			if(m.count(n)){
				cout<<"Already Exist"<<endl;
			}else{
				m[n]=n;
				//cout<<"OK"<<endl;
			}
		}else{
			if(!m.size()){
				cout<<"Empty"<<endl;
				continue;
			}
			auto t1=m.lower_bound(n);
			auto t2=--m.lower_bound(n);
		//	cout<<(*t1).first<<" "<<(*t2).first<<"         1"<<endl;
			if(t1==m.end()){
				cout<<abs((*t2).first)<<endl;
				m.erase((*t2).first);
			}else if(t1==m.begin()){
				cout<<abs((*t1).first)<<endl;
				m.erase((*t1).first);	
			}
			else{
				if(abs(n-(*t2).first)<=abs(n-(*t1).first)){			
					cout<<(*t2).first<<endl;
					m.erase((*t2).first);
				}else{
					cout<<(*t1).first<<endl;
					m.erase((*t1).first);	
				}
			}

		}
	}
}
